import React, { useState } from "react";
import Register from "./components/Register";
import Login from "./components/Login";
import Dashboard from "./components/Dashboard";
import AdminKycPanel from "./components/AdminKycPanel";

function App() {
  const [username, setUsername] = useState("");
  const [role, setRole] = useState("USER");
  const [loggedIn, setLoggedIn] = useState(false);

  const handleLoginSuccess = (user, userRole) => {
    setUsername(user);
    setRole(userRole || "USER");
    setLoggedIn(true);
  };

  if (!loggedIn) {
    return (
      <div className="auth-container">
        <h1>Secure Bank Portal</h1>
        <div className="auth-panels">
          <Register />
          <Login onSuccess={handleLoginSuccess} />
        </div>
      </div>
    );
  }

  if (role === "ADMIN") {
    return <AdminKycPanel username={username} onLogout={() => setLoggedIn(false)} />;
  }

  return <Dashboard username={username} onLogout={() => setLoggedIn(false)} />;
}

export default App;
